        rio_re[m*ms+4*ios] = x4_re; rio_im[m*ms+4*ios] = x4_im;
        rio_re[m*ms+5*ios] = x5_re; rio_im[m*ms+5*ios] = x5_im;
        rio_re[m*ms+6*ios] = x6_re; rio_im[m*ms+6*ios] = x6_im;
